import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import CaseCard from '../components/CaseCard';
import LoadingSpinner from '../components/LoadingSpinner';
import { casesData, Case } from '../data/cases';

const Home: React.FC = () => {
  const navigate = useNavigate();
  const [cases, setCases] = useState<Case[]>([]);
  const [filteredCases, setFilteredCases] = useState<Case[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [isLoading, setIsLoading] = useState(true);

  // Имитация загрузки данных (замените на реальный API-запрос)
  useEffect(() => {
    const timer = setTimeout(() => {
      setCases(casesData);
      setFilteredCases(casesData);
      setIsLoading(false);
    }, 800); // 0.8 сек – эффект загрузки

    return () => clearTimeout(timer);
  }, []);

  // Фильтрация при изменении категории или списка кейсов
  useEffect(() => {
    if (selectedCategory === 'all') {
      setFilteredCases(cases);
    } else {
      setFilteredCases(cases.filter(c => c.category === selectedCategory));
    }
  }, [selectedCategory, cases]);

  const handleCategoryChange = (category: string) => {
    setSelectedCategory(category);
  };

  // Категории для фильтрации
  const categories = [
    { key: 'all', label: 'Все' },
    { key: 'basic', label: 'Базовые' },
    { key: 'premium', label: 'Премиум' },
    { key: 'exclusive', label: 'Эксклюзив' },
    { key: 'game_specific', label: 'По играм' },
  ];

  if (isLoading) {
    return <LoadingSpinner />;
  }

  return (
    <>
      <h1>🎲 FazerCases</h1>

      {/* Панель фильтрации */}
      <div style={{ 
        display: 'flex', 
        gap: '10px', 
        marginBottom: '30px', 
        flexWrap: 'wrap',
        justifyContent: 'center'
      }}>
        {categories.map(cat => (
          <motion.button
            key={cat.key}
            onClick={() => handleCategoryChange(cat.key)}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            style={{
              background: selectedCategory === cat.key ? '#ffd700' : 'rgba(255,255,255,0.1)',
              color: selectedCategory === cat.key ? '#000' : '#fff',
              border: selectedCategory === cat.key ? '1px solid #ffd700' : '1px solid rgba(255,215,0,0.3)',
              padding: '8px 20px',
              borderRadius: '30px',
              cursor: 'pointer',
              fontSize: '1rem',
              fontWeight: selectedCategory === cat.key ? 'bold' : 'normal',
              backdropFilter: 'blur(10px)',
              transition: 'all 0.2s ease',
            }}
          >
            {cat.label}
          </motion.button>
        ))}
      </div>

      {/* Сетка кейсов с анимацией появления */}
      <motion.div
        className="cases-grid"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ staggerChildren: 0.1 }}
      >
        <AnimatePresence mode="wait">
          {filteredCases.map(caseItem => (
            <motion.div
              key={caseItem.id}
              layout
              initial={{ opacity: 0, y: 50 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -50 }}
              transition={{ type: 'spring', stiffness: 300, damping: 25 }}
            >
              <CaseCard
                caseData={caseItem}
                onOpen={() => navigate(`/case/${caseItem.id}`)}
              />
            </motion.div>
          ))}
        </AnimatePresence>
      </motion.div>

      {/* Сообщение, если кейсов нет */}
      {filteredCases.length === 0 && (
        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          style={{ textAlign: 'center', marginTop: '50px', color: '#999' }}
        >
          Кейсов в этой категории пока нет
        </motion.p>
      )}
    </>
  );
};

export default Home;
